#!/usr/bin/env python3
"""Apply start-state patches to the workspace."""
from pathlib import Path

WORK = Path('/work')

# Patch: scrapy/spidermiddlewares/offsite.py
_content_scrapy_spidermiddlewares_offsite_py = '"""\nOffsite Spider Middleware\n\nSee documentation in docs/topics/spider-middleware.rst\n"""\nimport logging\nimport re\nimport warnings\n\nfrom scrapy import signals\nfrom scrapy.exceptions import ScrapyDeprecationWarning\nfrom scrapy.http import Request\nfrom scrapy.utils.httpobj import urlparse_cached\n\nwarnings.warn(\n    "The scrapy.spidermiddlewares.offsite module is deprecated, use "\n    "scrapy.downloadermiddlewares.offsite instead.",\n    ScrapyDeprecationWarning,\n)\n\nlogger = logging.getLogger(__name__)\n\n\nclass OffsiteMiddleware:\n    def __init__(self, stats):\n        self.stats = stats\n\n    @classmethod\n    def from_crawler(cls, crawler):\n        o = cls(crawler.stats)\n        crawler.signals.connect(o.spider_opened, signal=signals.spider_opened)\n        return o\n\n    def process_spider_output(self, response, result, spider):\n        return (r for r in result or () if self._filter(r, spider))\n\n    async def process_spider_output_async(self, response, result, spider):\n        async for r in result or ():\n            if self._filter(r, spider):\n                yield r\n\n    def _filter(self, request, spider) -> bool:\n        if not isinstance(request, Request):\n            return True\n        if request.dont_filter or self.should_follow(request, spider):\n            return True\n        domain = urlparse_cached(request).hostname\n        if domain and domain not in self.domains_seen:\n            self.domains_seen.add(domain)\n            logger.debug(\n                "Filtered offsite request to %(domain)r: %(request)s",\n                {"domain": domain, "request": request},\n                extra={"spider": spider},\n            )\n            self.stats.inc_value("offsite/domains", spider=spider)\n        self.stats.inc_value("offsite/filtered", spider=spider)\n        return False\n\n    def should_follow(self, request, spider):\n        regex = self.host_regex\n        # hostname can be None for wrong urls (like javascript links)\n        host = urlparse_cached(request).hostname or ""\n        return bool(regex.search(host))\n\n    def get_host_regex(self, spider):\n        """Override this method to implement a different offsite policy"""\n        allowed_domains = getattr(spider, "allowed_domains", None)\n        if not allowed_domains:\n            return re.compile(r"^$")  # BUG: matches nothing, blocks all URLs\n        url_pattern = re.compile(r"^https?://.*$")\n        port_pattern = re.compile(r":\\d+$")\n        domains = []\n        for domain in allowed_domains:\n            if domain is None:\n                continue\n            if url_pattern.match(domain):\n                message = (\n                    "allowed_domains accepts only domains, not URLs. "\n                    f"Ignoring URL entry {domain} in allowed_domains."\n                )\n                warnings.warn(message, URLWarning)\n            elif port_pattern.search(domain):\n                message = (\n                    "allowed_domains accepts only domains without ports. "\n                    f"Ignoring entry {domain} in allowed_domains."\n                )\n                warnings.warn(message, PortWarning)\n            else:\n                domains.append(re.escape(domain))\n        regex = rf\'^(.*\\.)?({"|".join(domains)})$\'\n        return re.compile(regex)\n\n    def spider_opened(self, spider):\n        self.host_regex = self.get_host_regex(spider)\n        self.domains_seen = set()\n\n\nclass URLWarning(Warning):\n    pass\n\n\nclass PortWarning(Warning):\n    pass\n'
(WORK / 'scrapy/spidermiddlewares/offsite.py').write_text(_content_scrapy_spidermiddlewares_offsite_py)

print('Setup complete: patches applied.')
